solution_code:
#include <iostream>

void clamp(int& value, int lo, int hi) {
    if (value < lo) {
        value = lo;
    } else if (value > hi) {
        value = hi;
    }
}

int main() {
    int value, lo, hi;
    std::cin >> value >> lo >> hi;
    clamp(value, lo, hi);
    std::cout << value << '\n';
    return 0;
}

